+    /// Pre-evaluate and inline scalar subqueries in `expr` that reference
+    /// `target_table`. Replaces each matching `Expr::Subquery(...)` with a
+    /// literal of the evaluated result. This ensures the subquery runs against
+    /// the table's pre-DML state, not the partially-modified state during a
+    /// DELETE or UPDATE scan.
+    fn inline_self_referencing_scalar_subqueries(
+        &self,
+        expr: &mut Expr,
+        target_table: &str,
+    ) -> Result<()> {
+        match expr {
+            Expr::Subquery(subquery, _) if subquery_references_table(subquery, target_table) => {
+                let rows = self.execute_statement(
+                    &Statement::Select(subquery.as_ref().clone()),
+                    None,
+                )?;
+                let value = rows
+                    .first()
+                    .and_then(|r| r.values().first().cloned())
+                    .unwrap_or(SqliteValue::Null);
+                *expr = match value {
+                    SqliteValue::Null => {
+                        Expr::Literal(Literal::Null, fsqlite_ast::Span::ZERO)
+                    }
+                    SqliteValue::Integer(n) => {
+                        Expr::Literal(Literal::Integer(n), fsqlite_ast::Span::ZERO)
+                    }
+                    SqliteValue::Float(f) => {
+                        Expr::Literal(Literal::Float(f), fsqlite_ast::Span::ZERO)
+                    }
+                    SqliteValue::Text(s) => {
+                        Expr::Literal(Literal::String(s.to_string()), fsqlite_ast::Span::ZERO)
+                    }
+                    SqliteValue::Blob(b) => {
+                        Expr::Literal(
+                            Literal::Blob(b.to_vec()),
+                            fsqlite_ast::Span::ZERO,
+                        )
+                    }
+                };
+                Ok(())
+            }
+            Expr::BinaryOp { left, right, .. } => {
+                self.inline_self_referencing_scalar_subqueries(left, target_table)?;
+                self.inline_self_referencing_scalar_subqueries(right, target_table)
+            }
+            Expr::UnaryOp { expr: inner, .. }
+            | Expr::IsNull { expr: inner, .. }
+            | Expr::Cast { expr: inner, .. }
+            | Expr::Collate { expr: inner, .. } => {
+                self.inline_self_referencing_scalar_subqueries(inner, target_table)
+            }
+            Expr::FunctionCall { args: FunctionArgs::List(args), .. } => {
+                for arg in args.iter_mut() {
+                    self.inline_self_referencing_scalar_subqueries(arg, target_table)?;
+                }
+                Ok(())
+            }
+            _ => Ok(()),
+        }
+    }
