+/// Check if an expression contains an uncorrelated scalar subquery that
+/// references `outer_table` in its FROM clause — used to detect
+/// `DELETE FROM t WHERE val > (SELECT AVG(val) FROM t)` patterns.
+fn expr_has_self_referencing_scalar_subquery(expr: &Expr, outer_table: &str) -> bool {
+    match expr {
+        Expr::Subquery(subquery, _) => {
+            subquery_references_table(subquery, outer_table)
+        }
+        Expr::BinaryOp { left, right, .. } => {
+            expr_has_self_referencing_scalar_subquery(left, outer_table)
+                || expr_has_self_referencing_scalar_subquery(right, outer_table)
+        }
+        Expr::UnaryOp { expr: inner, .. }
+        | Expr::IsNull { expr: inner, .. }
+        | Expr::Cast { expr: inner, .. }
+        | Expr::Collate { expr: inner, .. } => {
+            expr_has_self_referencing_scalar_subquery(inner, outer_table)
+        }
+        Expr::FunctionCall { args: FunctionArgs::List(args), .. } => {
+            args.iter().any(|a| expr_has_self_referencing_scalar_subquery(a, outer_table))
+        }
+        _ => false,
+    }
+}
