+/// Check if a subquery references `table_name` in its FROM clause.
+fn subquery_references_table(subquery: &SelectStatement, table_name: &str) -> bool {
+    if let SelectCore::Select { from: Some(from), .. } = &subquery.body.select {
+        if let TableOrSubquery::Table { name, .. } = &from.source {
+            if name.name.eq_ignore_ascii_case(table_name) {
+                return true;
+            }
+        }
+        for join in &from.joins {
+            if let TableOrSubquery::Table { name, .. } = &join.table {
+                if name.name.eq_ignore_ascii_case(table_name) {
+                    return true;
+                }
+            }
+        }
+    }
+    false
+}
